#include <iostream>

class Point {
private:
    int x;
    int y;

public:
    Point() {
        x = 0;
        y = 0;
    }

    Point(int val_x, int val_y) {
        x = val_x;
        y = val_y;
    }

    int getX() {
        return x;
    }

    int getY() {
        return y;
    }
};

int main() {
    Point p1;
    std::cout << p1.getX() << " " << p1.getY() << std::endl;

    Point p2(5, 10);
    std::cout << p2.getX() << " " << p2.getY() << std::endl;

    Point p3(-3, 7);
    std::cout << p3.getX() << " " << p3.getY() << std::endl;

    return 0;
}
